"use strict";(globalThis.webpackChunkratel_docs=globalThis.webpackChunkratel_docs||[]).push([[496],{1071(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"category","label":"About Ratel","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/ko/intro/glossary","label":"\uc6a9\uc5b4 \uc815\ub9ac","docId":"intro/glossary","unlisted":false}],"href":"/ko/"},{"type":"link","href":"/ko/getting-started","label":"\uc2dc\uc791\ud558\uae30","docId":"getting-started","unlisted":false},{"type":"link","href":"/ko/ai-connect","label":"AI \uc5f0\uacb0","docId":"ai-connect","unlisted":false},{"type":"link","href":"/ko/teams","label":"\ud300 \uc0dd\uc131","docId":"teams","unlisted":false},{"type":"link","href":"/ko/posts","label":"\uac8c\uc2dc\uae00","docId":"posts","unlisted":false},{"type":"category","label":"Spaces","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/ko/spaces/apps","label":"\uc2a4\ud398\uc774\uc2a4 \uc571 (\ud638\uc2a4\ud2b8 \ub3c4\uad6c)","docId":"spaces/apps","unlisted":false},{"type":"link","href":"/ko/spaces/actions","label":"\uc2a4\ud398\uc774\uc2a4 \uc561\uc158","docId":"spaces/actions","unlisted":false},{"type":"link","href":"/ko/spaces/dashboard","label":"\uc2a4\ud398\uc774\uc2a4 \ub300\uc2dc\ubcf4\ub4dc (\ud638\uc2a4\ud2b8)","docId":"spaces/dashboard","unlisted":false},{"type":"link","href":"/ko/spaces/host-actions","label":"\ud638\uc2a4\ud2b8 \uc561\uc158 (\ud3b8\uc9d1\uae30)","docId":"spaces/host-actions","unlisted":false},{"type":"link","href":"/ko/spaces/reports","label":"\ub9ac\ud3ec\ud2b8 (\ud638\uc2a4\ud2b8)","docId":"spaces/reports","unlisted":false}],"href":"/ko/spaces"},{"type":"link","href":"/ko/profile","label":"\ud504\ub85c\ud544","docId":"profile","unlisted":false},{"type":"link","href":"/ko/settings","label":"\uc124\uc815","docId":"settings","unlisted":false},{"type":"link","href":"/ko/credentials","label":"\ud06c\ub9ac\ub374\uc15c","docId":"credentials","unlisted":false},{"type":"link","href":"/ko/my-essence","label":"\ub0b4 Essence","docId":"my-essence","unlisted":false},{"type":"link","href":"/ko/essence","label":"Essence \uc18c\uc2a4","docId":"essence","unlisted":false},{"type":"link","href":"/ko/rewards","label":"\ub9ac\uc6cc\ub4dc","docId":"rewards","unlisted":false},{"type":"link","href":"/ko/membership","label":"\uba64\ubc84\uc2ed","docId":"membership","unlisted":false},{"type":"link","href":"/ko/sub-teams","label":"\ud558\uc704\ud300 (Sub-teams)","docId":"sub-teams","unlisted":false},{"type":"link","href":"/ko/team-settings","label":"\ud300 \uc124\uc815","docId":"team-settings","unlisted":false}]},"docs":{"ai-connect":{"id":"ai-connect","title":"AI \uc5f0\uacb0","description":"Ratel\uc740 \uc0ac\uc6a9\uc790\ubcc4\ub85c \ud1b5\ud569 MCP \uc5d4\ub4dc\ud3ec\uc778\ud2b8 \ud558\ub098\ub97c \uc81c\uacf5\ud569\ub2c8\ub2e4. \ud3c9\uc18c \uc4f0\ub294 AI \ud074\ub77c\uc774\uc5b8\ud2b8\uc5d0 \uc5f0\uacb0\ud558\uba74, \uc5b4\uc2dc\uc2a4\ud134\ud2b8\uac00 \ub2f9\uc2e0\uc758 Essence \u2014 \uadf8\ub9ac\uace0 \ub2f9\uc2e0\uc774 \uad6c\ub3c5\ud55c \ub2e4\ub978 Essence House\ub4e4 \u2014 \uc744 \uc77c\uae09 \ub3c4\uad6c\ub85c \ud65c\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.","sidebar":"docsSidebar"},"credentials":{"id":"credentials","title":"\ud06c\ub9ac\ub374\uc15c","description":"\ud06c\ub9ac\ub374\uc15c(Credentials) \ud398\uc774\uc9c0\ub294 \ubcf8\uc778\uc774 \uc99d\uba85\ud55c \uac83\ub4e4\uc774 \ubaa8\uc774\ub294 \uacf3\uc785\ub2c8\ub2e4 \u2014 \ubd84\uc0b0 \uc2dd\ubcc4\uc790(DID), \uadf8 DID \uc5d0 \ubb36\uc778 \uac80\uc99d \uac00\ub2a5\ud55c \ud074\ub808\uc784\ub4e4, \uadf8\ub9ac\uace0 \uadf8 \ubaa8\ub4e0 \uac83\uc744 \ub4b7\ubc1b\uce68\ud558\ub294 \uc554\ud638\ud559\uc801 \uc99d\uba85. \uc2a4\ud398\uc774\uc2a4, Team, \uc678\ubd80 \uac80\uc99d\uc790\uc5d0\uac8c \uc120\ud0dd\uc801\uc73c\ub85c \uacf5\uac1c\ud560 \uc218 \uc788\ub294, \ud504\ub77c\uc774\ubc84\uc2dc\ub97c \ubcf4\uc874\ud558\ub294 \uc2e0\uc6d0 \uc18d\uc131 \uc9c0\uac11\uc774\ub77c\uace0 \ubcf4\uba74 \ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"essence":{"id":"essence","title":"Essence \uc18c\uc2a4","description":"Essence \uc5d0\ub294 \ucee8\ud2b8\ub864 \ud328\ub110\uc774 \uc788\uc2b5\ub2c8\ub2e4 \u2014 Essence \uc5d0 \ub4e4\uc5b4\uac00\ub294 \ubaa8\ub4e0 \uc785\ub825\uc744 \ud55c \ud398\uc774\uc9c0\uc5d0\uc11c \ubcf4\uace0, \uac80\uc0c9\ud558\uace0, \ub354 \uc774\uc0c1 \uc6d0\ud558\uc9c0 \uc54a\ub294 \ud56d\ubaa9\uc744 \uc815\ub9ac\ud560 \uc218 \uc788\uc5b4\uc694. \uc8fc\uc18c\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.","sidebar":"docsSidebar"},"getting-started":{"id":"getting-started","title":"\uc2dc\uc791\ud558\uae30","description":"Ratel \u2014 Human Essence Platform \uc5d0 \uc624\uc2e0 \uac83\uc744 \ud658\uc601\ud569\ub2c8\ub2e4. \uc774 \ucc55\ud130\ub294 Ratel \uc5d0\uc11c \ubcf4\ub0b4\ub294 \uccab\ub0a0\uc744 \uc548\ub0b4\ud569\ub2c8\ub2e4. \uac00\uc785\ubd80\ud130 \ud504\ub85c\ud544 \uc124\uc815, \uc678\ubd80 \uacc4\uc815 \uc5f0\uacb0, \uadf8\ub9ac\uace0 \ud654\uba74 \ub458\ub7ec\ubcf4\uae30\uae4c\uc9c0 \ud55c \ubc88\uc5d0 \uc9da\uc5b4\ub4dc\ub9b4\uac8c\uc694.","sidebar":"docsSidebar"},"intro/glossary":{"id":"intro/glossary","title":"\uc6a9\uc5b4 \uc815\ub9ac","description":"\ubcf8 \ubb38\uc11c\uc5d0 \ub4f1\uc7a5\ud558\ub294 Ratel \uc758 \ud575\uc2ec \uc6a9\uc5b4\ub4e4\uc744 \ube60\ub974\uac8c \ud655\uc778\ud560 \uc218 \uc788\ub3c4\ub85d \uc815\ub9ac\ud588\uc2b5\ub2c8\ub2e4. (\uc608\uc815) \ud45c\uc2dc\ub294 \ub85c\ub4dc\ub9f5 \ub2e8\uacc4\uc758 \uae30\ub2a5\uc774\ub77c\ub294 \ub73b\uc785\ub2c8\ub2e4 \u2014 \uae30\ubc18 \uc694\uc18c\ub294 \uc774\ubbf8 \uc874\uc7ac\ud560 \uc218 \uc788\uc9c0\ub9cc, \uc0ac\uc6a9\uc790\uac00 \ub9c8\uc8fc\ud558\ub294 \ud654\uba74\uc740 \uc544\uc9c1 \uc900\ube44 \uc911\uc785\ub2c8\ub2e4.","sidebar":"docsSidebar"},"intro/index":{"id":"intro/index","title":"Ratel \uc18c\uac1c","description":"Ratel\uc740 Human Essence Platform\uc785\ub2c8\ub2e4. \uc2e4\uc81c \uc0ac\ub78c\uc758 \uc0dd\uac01, \ud1b5\ucc30, \uadf8\ub9ac\uace0 \ud65c\ub3d9\uc744 \uae30\ub85d\ud558\uace0 \uc784\ubca0\ub529\ud558\uc5ec, \uc9c1\uc811 \ud65c\uc6a9\ud558\uace0 \uacf5\uc720\ud558\uba70 \uc218\uc775\ud654\ud560 \uc218 \uc788\ub294 \uac1c\uc778 \uc790\uc0b0\uc73c\ub85c \ub9cc\ub4e4\uc5b4 \uc8fc\ub294 \ud50c\ub7ab\ud3fc\uc785\ub2c8\ub2e4. \uc5ec\ub7ec\ubd84\uc774 \uc791\uc131\ud55c \uac8c\uc2dc\uae00, \ucc38\uc5ec\ud55c Space, \ub358\uc9c4 \ud22c\ud45c, \ub0a8\uae34 \ub313\uae00\uacfc \ud1a0\ub860\uc740 \ubaa8\ub450 \uc5ec\ub7ec\ubd84\uc758 Essence(\uc5d0\uc13c\uc2a4) \u2014 \ucc38\uc5ec\ud560\uc218\ub85d \uc790\uc5f0\uc2a4\ub7fd\uac8c \uc790\ub77c\ub098\ub294 \uac1c\uc778 \uc9c0\uc2dd \ubca0\uc774\uc2a4 \u2014 \uc758 \uc77c\ubd80\uac00 \ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"membership":{"id":"membership","title":"\uba64\ubc84\uc2ed","description":"\uba64\ubc84\uc2ed\uc740 \ud638\uc2a4\ud2b8\uc640 \ud30c\uc6cc \uc720\uc800\ub97c \uc704\ud55c Ratel \uc758 \ub4f1\uae09 \uc2dc\uc2a4\ud15c\uc785\ub2c8\ub2e4. \ub204\uad6c\ub098 \ubb34\ub8cc\ub85c \uac00\uc785\ud574\uc11c \ud50c\ub7ab\ud3fc\uc744 \uc0ac\uc6a9\ud560 \uc218 \uc788\uace0, \uc720\ub8cc \ub4f1\uae09\uc740 \ubcf4\uc0c1 \uc2a4\ud398\uc774\uc2a4\uc5d0 \uc0ac\uc6a9\ud560 \uc218 \uc788\ub294 \uc6d4\uac04 Credit, \ud06c\ub9ac\uc5d0\uc774\ud130 \ubc43\uc9c0, (\uc0c1\uc704 \ub4f1\uae09\uc5d0\uc11c\ub294) \ucc38\uc5ec\uc790 \uc6d0\ubcf8 \ub370\uc774\ud130 \uc5f4\ub78c \uad8c\ud55c\uc744 \ucd94\uac00\ub85c \uc7a0\uae08 \ud574\uc81c\ud569\ub2c8\ub2e4.","sidebar":"docsSidebar"},"my-essence":{"id":"my-essence","title":"\ub0b4 Essence","description":"Essence \ub294 \ucd94\uc0c1\uc801\uc778 \uac1c\ub150\uc774 \uc544\ub2d9\ub2c8\ub2e4 \u2014 \uc571 \uc548\uc5d0 \ub450 \uac1c\uc758 \uc804\uc6a9 \ud398\uc774\uc9c0\uac00 \uc788\uc5b4\uc11c, \ub0b4\uac00 \uc313\uc740 \uac83\uacfc \uadf8\uac83\uc774 \uac00\uc838\ub2e4\uc8fc\ub294 \uac83\uc744 \uc9c1\uc811 \ud655\uc778\ud560 \uc218 \uc788\uc5b4\uc694. My AI (/my-ai) \ub294 Ratel \uc744 \ub0b4 AI \uc5b4\uc2dc\uc2a4\ud134\ud2b8\uc5d0 \uc5f0\uacb0\ud558\ub294 \uacf3\uc785\ub2c8\ub2e4. Character (/me/character) \ub294 \ub0b4 \ud65c\ub3d9\uc774 \ub808\ubca8, \uc2a4\ud0ac \ud3ec\uc778\ud2b8, \uc2a4\ud0ef \ubd80\uc2a4\ud2b8\ub85c \ubcc0\ud558\ub294 \uacf3\uc785\ub2c8\ub2e4.","sidebar":"docsSidebar"},"posts":{"id":"posts","title":"\uac8c\uc2dc\uae00","description":"\uac8c\uc2dc\uae00\uc774 \uc911\uc694\ud55c \uc774\uc720","sidebar":"docsSidebar"},"profile":{"id":"profile","title":"\ud504\ub85c\ud544","description":"\ud504\ub85c\ud544\uc740 Ratel \uc5d0\uc11c \ub204\uad6c\ub4e0\uc9c0 \ub0b4 \uc774\ub984\uc744 \ub204\ub974\uac70\ub098 \ud578\ub4e4\uc744 \uc8fc\uc18c\ucc3d\uc5d0 \uc785\ub825\ud588\uc744 \ub54c \ub3c4\ucc29\ud558\ub294 \uacf5\uac1c \ud398\uc774\uc9c0\uc785\ub2c8\ub2e4. \uc8fc\uc18c\ub294 \ub2e4\uc74c\uacfc \uac19\uc544\uc694.","sidebar":"docsSidebar"},"rewards":{"id":"rewards","title":"\ub9ac\uc6cc\ub4dc","description":"\ub0b4\uac00 \ucc38\uc5ec\ud55c \ubaa8\ub4e0 \uc2a4\ud398\uc774\uc2a4, \ubc1c\ud589\ud55c \ubaa8\ub4e0 \uac8c\uc2dc\uae00, \ucc38\uc5ec\ub97c \ub04c\uc5b4\ub0b8 \ubaa8\ub4e0 \ub313\uae00\uc774 \u2014 \ub0b4 \uacc4\uc815\uc758 \ub9ac\uc6cc\ub4dc\ub85c \uc313\uc785\ub2c8\ub2e4. \ub9ac\uc6cc\ub4dc \ud398\uc774\uc9c0\ub294 \uadf8\ub3d9\uc548 \uc801\ub9bd\ud55c \uac83, \uc9c0\uae08 \uc801\ub9bd \uc911\uc778 \uac83, \uccad\uad6c \uac00\ub2a5\ud55c \uac83\uc744 \ud55c \ud654\uba74\uc5d0\uc11c \ud655\uc778\ud558\ub294 \uacf3\uc785\ub2c8\ub2e4.","sidebar":"docsSidebar"},"settings":{"id":"settings","title":"\uc124\uc815","description":"\uacc4\uc815\uc5d0 \uad00\ud55c \ubaa8\ub4e0 \uac83\uc744 \ud55c\uacf3\uc5d0\uc11c \ubc14\uafc0 \uc218 \uc788\ub294 \ud398\uc774\uc9c0\uc785\ub2c8\ub2e4 \u2014 \uc5b4\ub5bb\uac8c \ubcf4\uc77c\uc9c0, \uc5b4\ub5bb\uac8c \ub85c\uadf8\uc778\ud560\uc9c0, \uc5b4\ub5a4 \ud50c\ub79c\uc744 \uc4f8\uc9c0, AI \uc5d0\uc774\uc804\ud2b8\uac00 \ub0b4 Ratel \ub370\uc774\ud130\uc5d0 \uc5b4\ub5bb\uac8c \uc811\uc18d\ud560\uc9c0\uae4c\uc9c0.","sidebar":"docsSidebar"},"spaces/actions":{"id":"spaces/actions","title":"\uc2a4\ud398\uc774\uc2a4 \uc561\uc158","description":"Apps \uac00 \ud638\uc2a4\ud2b8\uc758 \ub3c4\uad6c\ud568\uc774\ub77c\uba74, \uc561\uc158(Action) \uc740 \ucc38\uc5ec\uc790\uc758 \ud018\uc2a4\ud2b8 \ubcf4\ub4dc\uc785\ub2c8\ub2e4. \uac01 \uc561\uc158\uc740 \ud638\uc2a4\ud2b8\uac00 \ubcf8\uc778\uc5d0\uac8c \ubd80\ud0c1\ud558\ub294 \ud55c \uac00\uc9c0 \uc77c\uc785\ub2c8\ub2e4 \u2014 \ubb34\uc5b8\uac00\uc5d0 \ud22c\ud45c\ud558\uae30, \ud1a0\ub860\uc5d0 \uc758\uacac \ub0a8\uae30\uae30, \ud034\uc988 \ud480\uae30, \uba87 \uba85 \ud314\ub85c\uc6b0\ud558\uae30, \ubbf8\ud305\uc5d0 RSVP \u2014 \uadf8\ub9ac\uace0 \uc561\uc158\uc744 \ub05d\ub0b4\uba74 \uc2a4\ud398\uc774\uc2a4 \ubcf4\uc0c1\uc758 \ud55c \ubaab\uc744 \uac00\uc838\uac00\uba74\uc11c, \ubcf8\uc778\uc774 \ubb34\uc5c7\uc744 \uc0dd\uac01\ud558\ub294\uc9c0\uc5d0 \ub300\ud55c \uad6c\uc870\ud654\ub41c \uc2e0\ud638\uac00 Essence \uc5d0 \uc313\uc785\ub2c8\ub2e4.","sidebar":"docsSidebar"},"spaces/apps":{"id":"spaces/apps","title":"\uc2a4\ud398\uc774\uc2a4 \uc571 (\ud638\uc2a4\ud2b8 \ub3c4\uad6c)","description":"\uc2a4\ud398\uc774\uc2a4\uc758 \ud638\uc2a4\ud2b8\ub77c\uba74, \uc571(App) \uc740 \uc2a4\ud398\uc774\uc2a4\ub97c \ub9cc\ub4e4\uae30 \uc704\ud574 \ub07c\uc6cc \ub123\ub294 \ube4c\ub529 \ube14\ub85d\uc785\ub2c8\ub2e4. \uac01 \uc571\uc740 \ud55c \uac00\uc9c0 \uc77c\uc744 \ub2f4\ub2f9\ud569\ub2c8\ub2e4 \u2014 \uc548\ub0b4 \uac8c\uc2dc, \ud30c\uc77c \uacf5\uc720, \ucc38\uc5ec\uc790\uc5d0\uac8c \ud22c\ud45c \uc694\uccad, AI \ubcf4\uc870 \ub9ac\ud3ec\ud2b8 \uc0dd\uc131, \ubcf4\uc0c1 \ubd84\ubc30 \u2014 \uc624\ub298 \ud544\uc694 \uc5c6\ub294 \uc571\uc740 \uadf8\ub0e5 \ube7c\ub450\uba74 \ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"spaces/dashboard":{"id":"spaces/dashboard","title":"\uc2a4\ud398\uc774\uc2a4 \ub300\uc2dc\ubcf4\ub4dc (\ud638\uc2a4\ud2b8)","description":"\ub300\uc2dc\ubcf4\ub4dc\ub294 \ud638\uc2a4\ud2b8\uc758 \\"\ub0b4 \uc2a4\ud398\uc774\uc2a4, \uc624\ub298 \uc5b4\ub5bb\uac8c \ub3cc\uc544\uac00\uace0 \uc788\ub098\\" \ud654\uba74\uc785\ub2c8\ub2e4 \u2014 \uc2a4\ud0ef \uce74\ub4dc \ud55c \ubb36\uc74c\uacfc \ucc38\uc5ec\uc790 \ub7ad\ud0b9 \ud45c\uac00 \ud55c \ud654\uba74\uc5d0 \ubaa8\uc5ec \uc788\uace0, \uc0ac\ub78c\ub4e4\uc774 \ud65c\ub3d9\ud560\uc218\ub85d \ub77c\uc774\ube0c\ub85c \uac31\uc2e0\ub429\ub2c8\ub2e4. \uc704\uce58\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.","sidebar":"docsSidebar"},"spaces/host-actions":{"id":"spaces/host-actions","title":"\ud638\uc2a4\ud2b8 \uc561\uc158 (\ud3b8\uc9d1\uae30)","description":"\uc774 \ucc55\ud130\ub294 \uc2a4\ud398\uc774\uc2a4 \uc561\uc158 \uc758 \ud638\uc2a4\ud2b8 \uce21 \uc9dd\uc785\ub2c8\ub2e4. \ucc38\uc5ec\uc790 \ucc55\ud130\uac00 \uc561\uc158\uc774 \ucc38\uc5ec\uc790\uc5d0\uac8c \uc5b4\ub5bb\uac8c \ubcf4\uc774\ub294\uc9c0 \ub97c \ub2e4\ub918\ub2e4\uba74, \uc774 \ucc55\ud130\ub294 \ud638\uc2a4\ud2b8\uc778 \ub2f9\uc2e0\uc774 \uac01 \uc561\uc158 \uc720\ud615\uc744 \uc5b4\ub5bb\uac8c \ub9cc\ub4e4\uace0 \ud3b8\uc9d1 \ud558\ub294\uc9c0\ub97c \uc548\ub0b4\ud569\ub2c8\ub2e4.","sidebar":"docsSidebar"},"spaces/index":{"id":"spaces/index","title":"\uc2a4\ud398\uc774\uc2a4","description":"\uc2a4\ud398\uc774\uc2a4\ub294 Ratel \ud65c\ub3d9\uc774 \uc77c\uc5b4\ub098\ub294 \uc544\ub808\ub098\uc785\ub2c8\ub2e4. \ud1a0\ub860, \ud22c\ud45c, \ud034\uc988, \ud314\ub85c\uc6b0 \ud018\uc2a4\ud2b8, \uc77c\uc815\uc774 \uc7a1\ud78c \ubbf8\ud305 \u2014 \ucee4\ubba4\ub2c8\ud2f0\ub97c \uce21\uc815 \uac00\ub2a5\ud55c \ub300\ud654\ub85c \ubc14\uafb8\ub294 \ubaa8\ub4e0 \ud65c\ub3d9\uc774 \uc2a4\ud398\uc774\uc2a4 \uc548\uc5d0\uc11c \ubc8c\uc5b4\uc9d1\ub2c8\ub2e4. \uc2a4\ud398\uc774\uc2a4\uc5d0\uc11c \ud638\uc2a4\ud2b8\ub294 \ucc38\uc5ec\uc790\uc5d0\uac8c \ubcf4\uc5ec\uc904 \ubaa8\uc2b5\uc744 \ub9cc\ub4e4\uace0, \ucc38\uc5ec\uc790\ub294 \ud65c\ub3d9\uc744 \ud1b5\ud574 Essence \ub97c \uc313\uc2b5\ub2c8\ub2e4.","sidebar":"docsSidebar"},"spaces/reports":{"id":"spaces/reports","title":"\ub9ac\ud3ec\ud2b8 (\ud638\uc2a4\ud2b8)","description":"\ub9ac\ud3ec\ud2b8(Report) \ub294 \ud638\uc2a4\ud2b8\uac00 \uc790\uc2e0\uc758 \uc2a4\ud398\uc774\uc2a4\uc5d0\uc11c \uc77c\uc5b4\ub09c \uc77c\uc744 \uc885\ud569\ud574 \ubc1c\ud589\ud558\ub294 \uacb0\uacfc\ubb3c\uc785\ub2c8\ub2e4 \u2014 \ucc38\uc5ec\uc790\ub4e4\uc774 \uc5b4\ub5bb\uac8c \uc0dd\uac01\ud588\uace0, \uc5b4\ub514\uc11c \ud569\uc758\ud588\uace0, \uc5b4\ub514\uc11c \uac08\ub838\uace0, \ubb34\uc5c7\uc774 \ub450\ub4dc\ub7ec\uc84c\ub294\uc9c0\ub97c \uc815\ub9ac\ud55c \ubb38\uc11c\uc608\uc694. Ratel \uc5d0\ub294 \ud568\uaed8 \ub3d9\uc791\ud558\ub294 \ub450 \uac1c\uc758 \ub9ac\ud3ec\ud2b8 \ud654\uba74\uc774 \uc788\uc2b5\ub2c8\ub2e4.","sidebar":"docsSidebar"},"sub-teams":{"id":"sub-teams","title":"\ud558\uc704\ud300 (Sub-teams)","description":"\ud558\uc704\ud300\uc740 \uc0c1\uc704 Team \uc774 \ub2e4\ub978 Team \uc744 \uc790\uc2e0\uc758 \uc6b0\uc0b0 \uc544\ub798\uc5d0 \uacf5\uc2dd\uc801\uc73c\ub85c \uc778\uc815\ud558\ub294 \ubc29\uc2dd\uc785\ub2c8\ub2e4 \u2014 \ucc55\ud130, \uc6cc\ud0b9 \uadf8\ub8f9, \ud30c\ud2b8\ub108 \uc140\ucc98\ub7fc \ud761\uc218\ud558\uc9c0 \uc54a\uc73c\uba74\uc11c \uad00\uacc4\ub97c \ub9fa\ub294 \uac70\uc608\uc694. \uc591\ucabd \ubaa8\ub450 \uc790\uc2e0\uc758 \uac8c\uc2dc\uae00, \uba64\ubc84, \ud2b8\ub808\uc800\ub9ac, \uc2a4\ud398\uc774\uc2a4\ub97c \uadf8\ub300\ub85c \uc720\uc9c0\ud558\uc9c0\ub9cc, \ub450 Team \uc0ac\uc774\uc758 \uad00\uacc4\ub294 \uaddc\uc815 \xb7 \ubb38\uc11c \xb7 \uacf5\uc9c0 \xb7 \ub204\uac00 \ub204\uad6c\uc758 \ud558\uc704\ud300\uc778\uc9c0\uc5d0 \ub300\ud55c \uacf5\uac1c \ub4f1\ub85d\ubd80\ub97c \uac16\ucd98 \ud50c\ub7ab\ud3fc \uc704\uc758 \ub9c1\ud06c \uac00 \ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"team-settings":{"id":"team-settings","title":"\ud300 \uc124\uc815","description":"\ud300 \uc124\uc815(Team Settings) \uc740 Team \uc758 \uad00\ub9ac\uc790\uac00 Team \uc790\uccb4\ub97c \uad00\ub9ac\ud558\ub294 \uacf3\uc785\ub2c8\ub2e4 \u2014 \uacf5\uac1c \uc815\uccb4\uc131, \uba64\ubc84\uc640 \uc5ed\ud560, \ub9e4\uc6d4 Credit \uc744 \uc9c0\uae09\ud558\ub294 \uad6c\ub3c5, \uadf8\ub9ac\uace0 (\ud544\uc694\ud558\ub2e4\uba74) \uc0ad\uc81c \ud750\ub984\uae4c\uc9c0. \uc774 \ud654\uba74\uc740 Team \uc758 \uad00\ub9ac\uc790(administrator) \uc2dc\uc810 \uc785\ub2c8\ub2e4 \u2014 \uacf5\uac1c \ud504\ub85c\ud544\uacfc \ud53c\ub4dc\ub294 \ud300 \ub9cc\ub4e4\uae30 \ucc55\ud130\ub97c \ucc38\uace0\ud558\uc138\uc694.","sidebar":"docsSidebar"},"teams":{"id":"teams","title":"\ud300 \uc0dd\uc131","description":"\uc65c \ud300\uc778\uac00\uc694?","sidebar":"docsSidebar"}}}}')}}]);